SELECT



    I.STATUS != 'INACTIVE'

        AND I.ITEM_NAME LIKE '%' || #{searchName} || '%'


        AND I.CATEGORY_ID = #{searchCategory}


        AND I.STATUS = #{searchStatus}


ORDER BY I.ITEM_ID DESC

